# Meeting Rooms II — O(n log n) time, O(n) space
# KEY INSIGHT: greedily reuse rooms — use min-heap of end times

import heapq

def minMeetingRooms(intervals):
    if not intervals:
        return 0

    intervals.sort(key=lambda x: x[0])
    heap = []  # min-heap of end times

    for start, end in intervals:
        if heap and heap[0] <= start:
            heapq.heapreplace(heap, end)  # reuse room (replace old end)
        else:
            heapq.heappush(heap, end)     # need new room

    return len(heap)

